<?php $conn = new mysqli('localhost', 'root', '', 'seal_hackathon'); $sql = 'SELECT l.id, l.admin_id as adminId, u.username as adminName, u.email as adminEmail, u.role as adminRole, l.action, l.target_type as targetType, l.target_id as targetId, l.description, l.ip_address as ipAddress, l.created_at as createdAt FROM admin_activity_logs l INNER JOIN users u ON u.id = l.admin_id ORDER BY l.created_at DESC'; $res = $conn->query($sql); if(!$res) echo 'Err: '.$conn->error; else echo 'Rows: '.$res->num_rows;
